3	import { useState, useMemo, Suspense } from "react";
4	import useSWR, { mutate } from "swr";
5	import {
6	  subscriptions as subsApi,
7	  channels as channelsApi,
8	  projects as projectsApi,
9	  sources as sourcesApi,
10	} from "@/lib/api/client";
11	import type { Source, Subscription } from "@/lib/api/types";
12	import { Plus, Pencil, Trash2 } from "lucide-react";
13	import { FilterBar, FilterConfig } from "@/components/filters/filter-bar";
14	import { useFilterParams } from "@/components/filters/use-filter-params";
15	import { Checkbox } from "@/components/ui/checkbox";
16	import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
17	import { ConfirmDialog } from "@/components/ui/confirm-dialog";
18	import { SubscriptionForm } from "@/components/subscriptions/subscription-form";
19	import { useTranslation } from "@/lib/i18n/context";
20	
21	
22	export default function SubscriptionsPage() {
23	  return (
24	    <Suspense>
25	      <SubscriptionsPageInner />
26	    </Suspense>
27	  );
28	}
29	
30	function SubscriptionsPageInner() {
31	  const { t } = useTranslation();
32	  const FILTER_KEYS = ["channel"];
33	  const { filters, setFilters } = useFilterParams(FILTER_KEYS);
34	  const { data, isLoading } = useSWR("subscriptions", () => subsApi.list());
35	  const { data: channelsData } = useSWR("channels-for-sub-list", () =>
36	    channelsApi.list()
37	  );
38	  const { data: projectsData } = useSWR("projects-for-sub-list", () =>
39	    projectsApi.list(1, 100)
40	  );
41	
42	  // Collect unique source IDs from subscriptions and fetch each one
43	  const sourceIds = useMemo(
44	    () =>
45	      Array.from(
46	        new Set(
47	          (data?.data ?? [])
48	            .filter((s) => s.type === "source_release" && s.source_id)
49	            .map((s) => s.source_id!)
50	        )
51	      ),
52	    [data]
53	  );
54	  const { data: sourcesMap } = useSWR(
55	    sourceIds.length > 0 ? `sources-for-sub-list-${sourceIds.join(",")}` : null,
56	    async () => {
57	      const results = await Promise.all(
58	        sourceIds.map((id) => sourcesApi.get(id).catch(() => null))
59	      );
60	      const map: Record<string, Source> = {};
61	      for (const r of results) {
62	        if (r?.data) map[r.data.id] = r.data;
63	      }
64	      return map;
65	    }
66	  );
67	
68	  const [createOpen, setCreateOpen] = useState(false);
69	  const [editingSub, setEditingSub] = useState<Subscription | null>(null);
70	  const [deletingId, setDeletingId] = useState<string | null>(null);
71	  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
72	  const [batchDeleteOpen, setBatchDeleteOpen] = useState(false);
73	
74	  const getChannelName = (id: string) =>
75	    channelsData?.data.find((c) => c.id === id)?.name ?? id;
76	
77	  const getProjectName = (id: string) =>
78	    projectsData?.data.find((p) => p.id === id)?.name ?? id;
79	
80	  const getSourceLabel = (id: string) => {
81	    const source = sourcesMap?.[id];
82	    return source ? `${source.provider}: ${source.repository}` : id;
83	  };
84	
85	  /* Build filter config */
86	  const filterConfig: FilterConfig[] = useMemo(() => [
87	    {
88	      key: "channel",
89	      label: "Channel",
90	      type: "select" as const,
91	      options: (channelsData?.data ?? []).map((c) => ({ value: c.id, label: c.name })),
92	    },
93	  ], [channelsData]);
94	
95	  /* Client-side filtering */
96	  const allSubscriptions = data?.data ?? [];
97	  const subscriptions = useMemo(() => {
98	    let result = allSubscriptions;
99	    if (filters.channel) {
100	      result = result.filter((s) => s.channel_id === filters.channel);
101	    }
102	    return result;
103	  }, [allSubscriptions, filters.channel, filters.type]);
104	
105	  const isAllSelected = subscriptions.length > 0 && selectedIds.size === subscriptions.length;
106	  const isSomeSelected = selectedIds.size > 0 && !isAllSelected;
107	
108	  const toggleSelect = (id: string) => {
109	    setSelectedIds((prev) => {
110	      const next = new Set(prev);
111	      if (next.has(id)) next.delete(id);
112	      else next.add(id);
113	      return next;
114	    });
115	  };
116	
117	  const toggleSelectAll = () => {
118	    if (isAllSelected) {
119	      setSelectedIds(new Set());
120	    } else {
121	      setSelectedIds(new Set(subscriptions.map((s) => s.id)));
122	    }
123	  };
124	
125	  const clearSelection = () => setSelectedIds(new Set());
126	
127	  return (
128	    <div className="space-y-6">
129	      {/* Header */}
130	      <div className="flex items-center justify-between">
131	        <div>
132	          <h1
133	            className="text-foreground"
134	            style={{
135	              fontFamily: "var(--font-raleway)",
136	              fontSize: "24px",
137	              fontWeight: 700,
138	            }}
139	          >
140	            {t("subscriptions.title")}
141	          </h1>
142	          <p className="mt-1 text-[13px] text-text-secondary" style={{ fontFamily: "var(--font-dm-sans)" }}>
143	            {t("subscriptions.description")}
144	          </p>
145	        </div>
146	        <button
147	          onClick={() => setCreateOpen(true)}
148	          className="inline-flex items-center gap-1.5 rounded-md px-3.5 py-2 transition-colors hover:opacity-90 bg-beacon-accent text-white"
149	          style={{
150	            fontFamily: "var(--font-dm-sans)",
151	            fontSize: "13px",
152	            fontWeight: 500,
153	          }}
154	        >
155	          <Plus className="h-4 w-4" />
156	          {t("subscriptions.newSubscription")}
157	        </button>
158	      </div>
159	
160	      {/* Filter ribbon */}
161	      <FilterBar filters={filterConfig} value={filters} onChange={setFilters} />
162	
163	      {isLoading ? (
164	        <div
165	          className="overflow-hidden rounded-lg bg-surface py-16 text-center border-border"
166	          style={{ border: "1px solid var(--border)", fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "var(--text-secondary)" }}
167	        >
168	          {t("subscriptions.loading")}
169	        </div>
170	      ) : subscriptions.length === 0 ? (
171	        <div
172	          className="overflow-hidden rounded-lg bg-surface py-16 text-center border-border"
173	          style={{ border: "1px solid var(--border)" }}
174	        >
175	          <p
176	            className="text-text-muted"
177	            style={{
178	              fontFamily: "var(--font-raleway)",
179	              fontStyle: "italic",
180	              fontSize: "15px",
181	            }}
182	          >
183	            {t("subscriptions.empty")}
184	          </p>
185	        </div>
186	      ) : (
187	        <div
188	          className="overflow-hidden rounded-lg bg-surface"
189	          style={{ border: "1px solid var(--border)" }}
190	        >
191	          <table className="w-full">
192	            <thead>
193	              <tr style={{ borderBottom: "1px solid var(--border)", backgroundColor: "var(--background)" }}>
194	                <th className="w-10 px-5 py-3 text-left">
195	                  <Checkbox
196	                    checked={isAllSelected ? true : isSomeSelected ? "indeterminate" : false}
197	                    onCheckedChange={toggleSelectAll}
198	                  />
199	                </th>
200	                {selectedIds.size > 0 ? (
201	                  <th colSpan={5} className="py-3 pr-5 text-left">
202	                    <div className="flex items-center">
203	                      <span
204	                        style={{
205	                          fontFamily: "var(--font-dm-sans)",
206	                          fontSize: "13px",
207	                          fontWeight: 500,
208	                          color: "var(--foreground)",
209	                        }}
210	                      >
211	                        {t("subscriptions.selected").replace("{count}", String(selectedIds.size)).replace("{total}", String(subscriptions.length))}
212	                      </span>
213	                      <span className="mx-3 h-4 w-px bg-border" />
214	                      <button
215	                        onClick={() => setBatchDeleteOpen(true)}
216	                        className="inline-flex items-center gap-1.5 rounded-md px-2.5 py-1 text-red-600 transition-colors hover:bg-red-50"
217	                        style={{
218	                          fontFamily: "var(--font-dm-sans)",
219	                          fontSize: "12px",
220	                          fontWeight: 500,
221	                        }}
222	                      >
223	                        <Trash2 className="h-3.5 w-3.5" />
224	                        {t("subscriptions.deleteSelected")}
225	                      </button>
226	                      <button
227	                        onClick={clearSelection}
228	                        className="ml-auto text-text-muted transition-colors hover:text-text-secondary"
229	                        style={{
230	                          fontFamily: "var(--font-dm-sans)",
231	                          fontSize: "12px",
232	                        }}
233	                      >
234	                        Cancel
235	                      </button>
236	                    </div>
237	                  </th>
238	                ) : (
239	                  ["Channel", t("subscriptions.thTarget"), t("subscriptions.thVersionFilter"), ""].map(
240	                    (heading, i) => (
241	                      <th
242	                        key={i}
243	                        className={`py-3 text-left ${i === 3 ? "w-20 px-5" : "px-5"}`}
244	                        style={{
245	                          fontFamily: "var(--font-dm-sans)",
246	                          fontSize: "11px",
247	                          fontWeight: 500,
248	                          textTransform: "uppercase",
249	                          letterSpacing: "0.08em",
250	                          color: "var(--text-muted)",
251	                        }}
252	                      >
253	                        {heading}
254	                      </th>
255	                    )
256	                  )
257	                )}
258	              </tr>
259	            </thead>
260	            <tbody>
261	              {subscriptions.map((sub) => (
262	                <tr
263	                  key={sub.id}
264	                  className="transition-colors hover:bg-background"
265	                  style={{ borderBottom: "1px solid var(--border)" }}
266	                >
267	                  <td className="w-10 px-5 py-3">
268	                    <Checkbox
269	                      checked={selectedIds.has(sub.id)}
270	                      onCheckedChange={() => toggleSelect(sub.id)}
271	                    />
272	                  </td>
273	
274	                  <td
275	                    className="px-5 py-3 text-foreground"
276	                    style={{
277	                      fontFamily: "var(--font-dm-sans)",
278	                      fontSize: "13px",
279	                      fontWeight: 500,
280	                    }}
281	                  >
282	                    {getChannelName(sub.channel_id)}
283	                  </td>
284	
285	                  <td
286	                    className="px-5 py-3 text-foreground"
287	                    style={{
288	                      fontFamily: "var(--font-dm-sans)",
289	                      fontSize: "14px",
290	                      fontWeight: 500,
291	                    }}
292	                  >
293	                    {sub.source_id
294	                      ? getSourceLabel(sub.source_id)
295	                      : sub.project_id ? getProjectName(sub.project_id) : "\u2014"}
296	                  </td>
297	
298	                  <td
299	                    className="px-5 py-3"
300	                    style={{
301	                      fontFamily: sub.version_filter
302	                        ? "'JetBrains Mono', monospace"
303	                        : "var(--font-dm-sans)",
304	                      fontSize: "13px",
305	                      color: sub.version_filter ? "var(--foreground)" : "var(--text-muted)",
306	                    }}
307	                  >
308	                    {sub.version_filter || "\u2014"}
309	                  </td>
310	
311	                  <td className="w-20 px-5 py-3">
312	                    <div className="flex items-center gap-2">
313	                      <button
314	                        onClick={() => setEditingSub(sub)}
315	                        className="rounded p-1 text-text-muted transition-colors hover:bg-mono-bg hover:text-foreground"
316	                      >
317	                        <Pencil className="h-4 w-4" />
318	                      </button>
319	                      <button
320	                        onClick={() => setDeletingId(sub.id)}
321	                        className="rounded p-1 text-text-muted transition-colors hover:bg-red-50 hover:text-red-600"
322	                      >
323	                        <Trash2 className="h-4 w-4" />
324	                      </button>
325	                    </div>
326	                  </td>
327	                </tr>
328	              ))}
329	            </tbody>
330	          </table>
331	        </div>
332	      )}
333	
334	      {/* Create dialog */}
335	      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
336	        <DialogContent className="sm:max-w-lg">
337	          <DialogHeader>
338	            <DialogTitle>{t("subscriptions.createSubscription")}</DialogTitle>
339	          </DialogHeader>
340	          <SubscriptionForm
341	            title={t("subscriptions.createSubscription")}
342	            onSubmit={async (input) => {
343	              await subsApi.create(input);
344	            }}
345	            onBatchSubmit={async (input) => {
346	              await subsApi.batchCreate(input);
347	            }}
348	            onSuccess={() => {
349	              setCreateOpen(false);
350	              mutate("subscriptions");
351	              clearSelection();
352	            }}
353	            onCancel={() => setCreateOpen(false)}
354	          />
355	        </DialogContent>
356	      </Dialog>
357	
358	      {/* Edit dialog */}
359	      <Dialog
360	        open={!!editingSub}
361	        onOpenChange={(open) => {
362	          if (!open) setEditingSub(null);
363	        }}
364	      >
365	        <DialogContent className="sm:max-w-lg">
366	          <DialogHeader>
367	            <DialogTitle>{t("subscriptions.editSubscription")}</DialogTitle>
368	          </DialogHeader>
369	          {editingSub && (
370	            <SubscriptionForm
371	              key={editingSub.id}
372	              title={t("subscriptions.editSubscription")}
373	              initial={editingSub}
374	              onSubmit={async (input) => {
375	                await subsApi.update(editingSub.id, input);
376	              }}
377	              onSuccess={() => {
378	                setEditingSub(null);
379	                mutate("subscriptions");
380	                clearSelection();
381	              }}
382	              onCancel={() => setEditingSub(null)}
383	            />
384	          )}
385	        </DialogContent>
386	      </Dialog>
387	
388	      {/* Delete dialog */}
389	      <ConfirmDialog
390	        open={!!deletingId}
391	        onOpenChange={(open) => {
392	          if (!open) setDeletingId(null);
393	        }}
394	        title={t("subscriptions.deleteSubscription")}
395	        description={t("subscriptions.deleteSubscriptionDesc")}
396	        onConfirm={async () => {
397	          if (deletingId) {
398	            await subsApi.delete(deletingId);
399	            mutate("subscriptions");
400	            clearSelection();
401	          }
402	        }}
403	      />
404	
405	      {/* Batch delete dialog */}
406	      <ConfirmDialog
407	        open={batchDeleteOpen}
408	        onOpenChange={setBatchDeleteOpen}
409	        title={t("subscriptions.deleteSubscriptions")}
410	        description={t("subscriptions.deleteSubscriptionsDesc").replace("{count}", String(selectedIds.size))}
411	        onConfirm={async () => {
412	          await subsApi.batchDelete({ ids: [...selectedIds] });
413	          mutate("subscriptions");
414	          clearSelection();
415	        }}
416	      />
417	    </div>
418	  );
419	}
