              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "12px" }}>
                {source.repository}
              </span>
            </div>
            <div className="mt-2 flex flex-wrap items-center gap-1.5">
              {subs.length === 0 && (
                <span className="text-[12px] text-text-muted">{t("projects.detail.noSubscriptions")}</span>
