              {subs.slice(0, 5).map((sub) => (
                <button
                  key={sub.id}
                  onClick={() => setEditingSub(sub)}
                  className="inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-medium leading-none bg-mono-bg text-secondary-foreground hover:bg-mono-bg/80 transition-colors cursor-pointer"
                  title={t("projects.detail.editSubscription")}
                >
                  <Bell className="h-3 w-3" />
                  {channelMap.get(sub.channel_id) ?? sub.channel_id}
                  {sub.version_filter && (
                    <span className="text-text-muted" style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "10px" }}>
                      {sub.version_filter}
                    </span>
                  )}
                  <Pencil className="h-2.5 w-2.5 text-text-muted" />
                </button>
              ))}
              {subs.length > 5 && (
                <Link
                  href="/subscriptions"
                  className="text-[11px] font-medium hover:underline text-beacon-accent"
                  style={{ fontFamily: "var(--font-dm-sans)" }}
                >
                  {t("projects.more")}
